const stats = $input.first().json;
const hotStocks = $input.all()[1].json.stocks || [];

const today = new Date().toISOString().split('T')[0];
const todayData = stats.daily?.[today] || {visits: 0, analyses: 0};

const dashboard = {
  updated_at: new Date().toISOString(),
  total_visits: stats.total_visits || 0,
  total_analyses: stats.total_analyses || 0,
  today_visits: todayData.visits,
  today_analyses: todayData.analyses,
  hot_stocks: hotStocks.map(s => ({
    code: s.code,
    name: s.name,
    price: s.price,
    change_pct: s.change_pct
  })),
  recent_7days: Object.entries(stats.daily || {})
    .sort((a,b) => b[0].localeCompare(a[0]))
    .slice(0,7)
    .map(([date, data]) => ({
      date,
      visits: data.visits,
      analyses: data.analyses
    }))
};

return [{json: dashboard}];

const data = $input.first().json;

// 生成简单的HTML报告
const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>股小智数据看板</title>
<style>
body{font-family:-apple-system,BlinkMacSystemFont,sans-serif;background:#0d1117;color:#c9d1d9;padding:24px;max-width:900px;margin:0 auto}
.metric{display:inline-block;background:#161b22;border:1px solid #30363d;border-radius:8px;padding:16px 24px;margin:8px;text-align:center}
.metric-value{font-size:28px;font-weight:800;color:#58a6ff}
.metric-label{font-size:12px;color:#8b949e;margin-top:4px}
.stock-item{padding:8px 0;border-bottom:1px solid #21262d}
.up{color:#3fb950}.down{color:#f85149}
</style></head><body>
<h1>📊 股小智实时看板</h1><p style="color:#8b949e">更新时间: ${data.updated_at}</p>
<div>
<div class="metric"><div class="metric-value">${data.total_visits}</div><div class="metric-label">累计访问</div></div>
<div class="metric"><div class="metric-value">${data.total_analyses}</div><div class="metric-label">AI分析次数</div></div>
<div class="metric"><div class="metric-value">${data.today_visits}</div><div class="metric-label">今日访问</div></div>
<div class="metric"><div class="metric-value">${data.today_analyses}</div><div class="metric-label">今日分析</div></div>
</div>
<h3>🔥 热门股票</h3>
${data.hot_stocks.map(s => 
  `<div class="stock-item">${s.name}(${s.code}) <span class="${parseFloat(s.change_pct)>0?'up':'down'}">${s.change_pct}%</span> 价格:${s.price}</div>`
).join('')}
</body></html>`;

return [{json: {html, filename: `dashboard-${data.updated_at.split('T')[0]}.html`}}];
